WITH admin_role AS (SELECT id FROM roles WHERE code = 'admin'), inserted_admin AS (INSERT INTO users (role_id, first_name, last_name, email, password_hash, academy_member, status) SELECT admin_role.id, 'Admin', 'Root', '__DEFAULT_ADMIN_EMAIL__', '__DEFAULT_ADMIN_PASSWORD_HASH__', TRUE, 'active' FROM admin_role WHERE NOT EXISTS (SELECT 1 FROM users WHERE email = '__DEFAULT_ADMIN_EMAIL__') RETURNING id) INSERT INTO wallets (user_id, balance_credits) SELECT id, 999 FROM inserted_admin ON CONFLICT (user_id) DO NOTHING;
